## Output

A short JSON object summarizing what was added. When the additions touched multiple sections, group them under `sections`:

```json
{
  "post_id": "...",
  "sections": [
    {"sec_id": "architectures-of-the-past", "added": ["bullet on RNN world models", "bullet on memory-augmented networks"]},
    {"sec_id": "recent-innovations", "added": ["hero image showing the architecture lineage"]}
  ]
}
```

def add_policy(self, flow, state, context, tools):
    if not flow.slots['source'].check_if_filled():
        self.ambiguity.declare('specific', metadata={'missing_slot': flow.entity_slot})
        return DisplayFrame(flow.name())

    post_id, _ = self._resolve_source_ids(flow, state, tools)

    text, tool_log = self.llm_execute(flow, state, context, tools)
    parsed = self.engineer.apply_guardrails(text) or {}

    if parsed.get('fallback'):
        self.flow_stack.fallback(parsed['fallback'])
        state.keep_going = True
        return DisplayFrame(flow.name(),
            thoughts=parsed.get('reason', ''),
            metadata={'fallback': parsed['fallback']})

    saved, _ = self.engineer.tool_succeeded(tool_log, 'revise_content')
    saved_media, _ = self.engineer.tool_succeeded(tool_log, 'insert_media')
    if not (saved or saved_media):
        return self.error_frame(flow, 'failed_to_save',
            thoughts='Neither revise_content nor insert_media landed.',
            code=text,
            failed_tool='revise_content')

    flow.status = 'Completed'
    frame = DisplayFrame(flow.name(),
        thoughts=text,
        metadata={
            'post_id': post_id,
            'sections_touched': [s['sec_id'] for s in parsed.get('sections', [])],
            'insertions_count': sum(len(s.get('added', [])) for s in parsed.get('sections', [])),
        })
    frame.add_block({'type': 'card', 'data': self._read_post_content(post_id, tools)})
    return frame
